using UnityEngine;

/// <summary>
/// Ponto único de referência ao Transform do player em runtime (Task #19 —
/// "Identificação do Player inconsistente entre scripts").
///
/// Attach este componente no GameObject do player (junto com PlayerInputRouter,
/// PlayerMotor2D, etc.). Ao fazer Awake, regista-se em <see cref="Instance"/>;
/// ao ser destruído (ex: recarregar cena), limpa o registo.
///
/// Todos os scripts que precisem de localizar o player devem usar:
///   <code>PlayerLocator.Find()</code>   — Transform (com fallback a FindGameObjectWithTag)
///   <code>PlayerLocator.Instance</code>  — Transform directo (null se não registado)
///   <code>PlayerLocator.GameObject</code>— GameObject directo (null se não registado)
///
/// Substitui as chamadas dispersas a
/// <c>GameObject.FindGameObjectWithTag("Player")</c> /
/// <c>GameObject.FindWithTag("Player")</c> que apareciam em
/// NpcController, NpcMovement, EnemyController, ChallengeManager,
/// SaveManager, ChallengeTrigger, ChallengeActions, FormLockActions,
/// NightVisionRevealable, FallingPlatform, etc.
///
/// Não usa DontDestroyOnLoad — segue o ciclo de vida normal da cena.
/// </summary>
[DefaultExecutionOrder(-100)]   // regista antes de scripts que o consultam em Awake
public class PlayerLocator : MonoBehaviour
{
    /// <summary>Transform do player registado, ou null se nenhum player estiver activo.</summary>
    public static Transform Instance { get; private set; }

    /// <summary>GameObject do player registado, ou null se nenhum player estiver activo.</summary>
    public static GameObject GameObject => Instance != null ? Instance.gameObject : null;

    // Task #11: limpa a referência estática ao entrar em Play Mode, mesmo com
    // "Enter Play Mode Options > Domain Reload" desactivado. Sem isto,
    // Instance poderia apontar para um Transform destruído da sessão anterior
    // (Unity anula a referência ao destruir, mas é mais explícito resetar aqui).
    [RuntimeInitializeOnLoadMethod(RuntimeInitializeLoadType.SubsystemRegistration)]
    private static void ResetStatics() => Instance = null;

    private void Awake()
    {
        if (Instance != null && Instance != transform)
            Debug.LogWarning($"[PlayerLocator] Dois players detectados: '{Instance.name}' e '{name}'. A substituir pelo novo.", this);

        Instance = transform;
    }

    private void OnDestroy()
    {
        if (Instance == transform)
            Instance = null;
    }

    /// <summary>
    /// Devolve o Transform do player.
    /// Se <see cref="Instance"/> não estiver registado (ex: script chamado antes
    /// do Awake do player, ou PlayerLocator não está no prefab), faz fallback a
    /// <c>GameObject.FindGameObjectWithTag("Player")</c> e avisa no Console —
    /// idealmente o fallback nunca deve ocorrer em produção.
    /// </summary>
    public static Transform Find()
    {
        if (Instance != null) return Instance;

        var go = UnityEngine.GameObject.FindGameObjectWithTag("Player");
        if (go != null)
        {
            Debug.LogWarning("[PlayerLocator] Instance não registado — fallback a FindGameObjectWithTag. " +
                             "Adiciona PlayerLocator ao prefab do player.", go);
            return go.transform;
        }

        return null;
    }
}
